                else {

                    lazyflag[l] = true;

                    lazy[l] = x;

                }

                l++;

            }

            if (r & 1) {

                r--;

                updf(node[r], x, width[r]);

                if (lazyflag[r])lazyf(lazy[r], x);

                else {

                    lazyflag[r] = true;

                    lazy[r] = x;

                }

            }

            l >>= 1; r >>= 1;

        }

